@page "/inventory"
@using InventoryApp.Models
@using InventoryApp.Services
@rendermode InteractiveServer
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        // During the interactive render, try to restore data that was
        // persisted from the prerender pass — avoids a second service call.
        _persistSub = ApplicationState.RegisterOnPersisting(PersistData);

        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>(
                nameof(_items), out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentSvc.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson(nameof(_items), _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistSub.Dispose();
    }
}

